const required = [
  "channel",
  "external_order_id",
  "customer_email",
  "customer_name",
  "created_at",
  "payment_status",
  "total_amount",
  "sku_list",
  "qty_total"
];

const errors = [];
for (const k of required) {
  const v = $json[k];
  if (v === undefined || v === null || String(v).trim() === "") errors.push(`missing_${k}`);
}

// normalize yes/no fields
const hold = ($json.hold_review ?? "no").toString().trim().toLowerCase();
const hold_review = (hold === "yes" || hold === "true") ? "yes" : "no";

const payment = ($json.payment_status ?? "").toString().trim().toLowerCase();
const allowedPayments = ["paid", "pending", "failed", "refunded"];
if (payment && !allowedPayments.includes(payment)) errors.push("invalid_payment_status");

return [{
  json: {
    ...$json,
    hold_review,
    payment_status: payment,
    is_valid: errors.length === 0,
    errors
  }
}];
